h-zoom: ; --tw-scroll-snap-strictness: proximity; --tw-gradient-from-position: ; --tw-gradient-via-position: ; --tw-gradient-to-position: ; --tw-ordinal: ; --tw-slashed-zero: ; --tw-numeric-figure: ; --tw-numeric-spacing: ; --tw-numeric-fraction: ; --tw-ring-inset: ; --tw-ring-offset-width: 0px; --tw-ring-offset-color: #fff; --tw-ring-color: rgb(59 130 246 / .5); --tw-ring-offset-shadow: 0 0 #0000; --tw-ring-shadow: 0 0 #0000; --tw-shadow: 0 0 #0000; --tw-shadow-colored: 0 0 #0000; --tw-blur: ; --tw-brightness: ; --tw-contrast: ; --tw-grayscale: ; --tw-hue-rotate: ; --tw-invert: ; --tw-saturate: ; --tw-sepia: ; --tw-drop-shadow: ; --tw-backdrop-blur: ; --tw-backdrop-brightness: ; --tw-backdrop-contrast: ; --tw-backdrop-grayscale: ; --tw-backdrop-hue-rotate: ; --tw-backdrop-invert: ; --tw-backdrop-opacity: ; --tw-backdrop-saturate: ; --tw-backdrop-sepia: ; --tw-contain-size: ; --tw-contain-layout: ; --tw-contain-paint: ; --tw-contain-style: ; border-width: 2px; border-color: rgb(107, 114, 128); border-image: initial; border-radius: 6px; padding: 12px; margin: 8px 0px; display: inline-block; min-width: 100px;">Aproximadamente 5,08 procedimentos/mês</div></font></div><div><div style="background-color: rgb(249, 250, 251); border: 2px solid rgb(107, 114, 128); border-radius: 6px; padding: 12px; margin: 8px 0px; display: inline-block; min-width: 100px;">Aproximadamente 5,08 procedimentos/mês</div><div><div style="background-color: rgb(250, 245, 255); border: 2px solid rgb(168, 85, 247); border-radius: 6px; padding: 12px; margin: 8px 0px; display: inline-block; min-width: 100px;">Sistema de rodízio por ordem cronológica de credenciamento, alternando a cada usuário</div><div><br></div><div></div><div style="background-color: rgb(255, 251, 235); border: 2px solid rgb(245, 158, 11); border-radius: 6px; padding: 12px; margin: 8px 0px; display: inline-block; min-width: 100px;">LOCAL DE EXECUÇÃO:&nbsp;Hospital Municipal São José&nbsp;- Joinville/SC</div><div><br></div><div><br></div>UrL  https://www.in.gov.br/web/dou/-/aviso-de-alteracao-682630906  Objeto: O Município de Joinville através da Unidade de Licitações da Secretaria de Administração e Planejamento, leva ao conhecimento dos interessados que em conformidade com o que preceitua a Lei Federal nº 14.133/2021, está promovendo alterações no processo licitatório de Credenciamento nº 218/2025 destinado ao Credenciamento de pessoas físicas e/ou jurídicas prestadoras de serviços médicos em Oftalmologia, na especialidade de transplantes de córneas e atividades correlacionadas, a fim de atender à demanda dos usuários do Sistema Único de Saúde no Município de Joinville, especificamente no Hospital Municipal São José. O edital consolidado encontra-se à disposição dos interessados no site www.joinville.sc.gov.br no link ''Editais de Licitação''. Silvia Cristina Bello Diretora Executiva</div></div></div></div></div>', 'VALOR BAIXO'),
('a7231801-316b-4bbc-9874-876a9eda0258', 'eaa36aab-c14b-4de5-9bf0-43a23d1a2642', 'cdadda91-19f6-4aad-897b-10ed70fb65f6', 'Pregão para Radiologia em Crato (CE) Um pregão para radiologia em
consórcio na cidade de Crato, Ceará, foi analisado. O pregão envolvia o
fornecimento de equipamento de ultrassonografia e Doppler, com laudos em
até 24 horas. O valor unitário de R$ 59 e o volume de 3.000 ultrassons anuais,
sendo 250 por mês, foram considerados muito baixos, resultando no descarte
do processo (00:32:01).', '2026-02-03T11:40:43.937Z', '3adafddc-3d23-40c6-8ce0-5ddf0d3aef0b', 'Luana Barros', '263970', NULL, 'Crato', 'Crato', 'Pregão Eletrônico', '7203734', 'UrL <mark>https://cnetmobile.estaleiro.serpro.gov.br/comprasnet-web/public/landing?destino=acompanhamento-compra&amp;compra=92953205920032026</mark> <br> Objeto: Contratação de empresa especializada para a execução de exames de ultrassonografia convencional e ultrassonografia com doppler, de forma complementar, para atender as necessidades das unidades de saúde gerenciadas pelo Consórcio Público de Saúde da Microrregião de Crato  CPSMC, conforme condições, quantidades e exigências estabelecidas neste Edital e seus anexos. -fim<div><br></div><div></div><div style="background-color: rgb(239, 246, 255); border: 2px solid rgb(59, 130, 246); border-radius: 6px; padding: 12px; margin: 8px 0px; display: inline-block; min-width: 100px;"><b>CRATO/CE FICA A 30MIN DE JUAZEIRO/CE</b></div><div><br></div><div><font color="#dc2626"></font></div><div style="background-color: rgb(249, 250, 251); border: 2px solid rgb(107, 114, 128); border-radius: 6px; padding: 12px; margin: 8px 0px; display: inline-block; min-width: 100px;"><b><font color="#dc2626">&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;laudo médico com imagens em até 24h&lt;&lt;&lt;&lt;&lt;&lt;&lt;&lt;&lt;&lt;&lt;&lt;</font></b></div><div><br></div><font color="#dc2626"><b><div style="background-color: rgb(239, 246, 255); border: 2px solid rgb(59, 130, 246); border-radius: 6px; padding: 12px; margin: 8px 0px; display: inline-block; min-width: 100px;">FORNECER: equipamentos de ultrassonografia e doppler&nbsp;</div></b></font><div><span style="background-color: rgb(255, 251, 235); font-size: 0.875rem; color: rgb(12, 54, 14);"></span><div style="background-color: rgb(250, 245, 255); border: 2px solid rgb(168, 85, 247); border-radius: 6px; padding: 12px; margin: 8px 0px; display: inline-block; min-width: 100px;">3.000 USG ultrassonografias = 250/MÊS - VALOR UNIT: R$59,67</div><div><div style="background-color: rgb(250, 245, 255); border: 2px solid rgb(168, 85, 247); border-radius: 6px; padding: 12px; margin: 8px 0px; display: inline-block; min-width: 100px;">1.000 USG com doppler = 83/ MÊS - VALOR UNIT R$84,96</div><div><br></div><div>Qual será o local de execução?&nbsp;Policlínica Aderson Tavares Bezerra (Crato/CE) e Policlínica Bárbara Pereira de Alencar</div></div></div><div><br></div>', 'VALOR BAIXO'),
