('8fd56cce-789f-43a9-a47b-b5dfac9f1686', '350f5065-8427-4361-bdc6-e7379f17215a', 'a146e03a-41d0-46b3-bb95-ca3faf0931a5', 'Oportunidade para Sete Hospitais no Mato Grosso (MT) : Um grande processo para sete hospitais estaduais em municípios do Mato Grosso, incluindo Cuiabá e Várzea Grande, foi apresentado. Os serviços médicos são majoritariamente para Neurologia Pediátrica, o que foi prontamente rejeitado por ser considerado um tipo de serviço muito problemático ( 00:20:39 ).', '2026-03-24T18:13:04.642Z', '3adafddc-3d23-40c6-8ce0-5ddf0d3aef0b', 'Luana Barros', NULL, NULL, 'Cuiabá', 'Cuiabá', 'Pregão Eletrônico', '7401326', '<div></div><div data-highlight-box="true" style="background-color: rgb(240, 253, 244); border: 2px solid rgb(34, 197, 94); border-radius: 6px; padding: 12px; margin: 8px 0px; display: block; min-width: 100px;"><div><b><font color="#dc2626">CUIABÁ/MT</font></b></div><div></div></div><div data-highlight-box="true" style="background-color: rgb(240, 253, 244); border: 2px solid rgb(34, 197, 94); border-radius: 6px; padding: 12px; margin: 8px 0px; display: block; min-width: 100px;"><div><b><font color="#dc2626">LOCAL DE EXECUÇÃO:&nbsp;</font></b><span style="font-weight: 600; color: rgb(15, 17, 21); font-family: quote-cjk-patch, Inter, system-ui, -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Oxygen, Ubuntu, Cantarell, &quot;Open Sans&quot;, &quot;Helvetica Neue&quot;, sans-serif; font-size: 15px; background-color: rgb(255, 255, 255);">7 hospitais estaduais</span><span style="color: rgb(15, 17, 21); font-family: quote-cjk-patch, Inter, system-ui, -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Oxygen, Ubuntu, Cantarell, &quot;Open Sans&quot;, &quot;Helvetica Neue&quot;, sans-serif; font-size: 15px; background-color: rgb(255, 255, 255);">&nbsp;em diferentes municípios: Cuiabá, Várzea Grande, Alta Floresta, Rondonópolis, Sinop, Sorriso e Colíder.</span></div><div></div></div><div data-highlight-box="true" style="backgro